/**
 * Catalogo del Core NIST CSF 2.0 (NIST.CSWP.29, Anexo A, feb 2024).
 * 106 subcategorias oficiales (la numeracion del estandar no es consecutiva).
 *
 * Ejemplos de implementacion (contenido local, opcional):
 * En cada fila de CSF_CATALOG_ITEMS puedes agregar la propiedad
 *   implementationExamplesEs: ["texto ejemplo 1", "texto ejemplo 2", ...]
 * - Cada string del array es UN ejemplo (como Ex1, Ex2 en documentos NIST).
 * - Puede haber uno o muchos por subcategoria.
 * - Si omites la propiedad, en resultados no se muestra nada extra (no abarrota).
 * - En resultados, bajo cada subcategoria: enlace "Ver orientacion..." y lista desplegable debajo.
 * - outcomeEs (opcional): traduccion al español del Outcome del Anexo A; se usa en la tabla "Core CSF completo".
 */
export type CsfFunctionCode = "GV" | "ID" | "PR" | "DE" | "RS" | "RC";

export interface CsfCatalogItem {
  id: string;
  phase: number;
  function: CsfFunctionCode;
  categoryKey: string;
  categoryEs: string;
  outcomeEn: string;
  /** Outcome del Core en español (Anexo A). Opcional: rellenalo en cada fila de CSF_CATALOG_ITEMS. */
  page: string;
  outcomeEs?: string;
  questionEs: string;
  /** Uno o mas ejemplos ilustrativos en español; opcional. */
  implementationExamplesEs?: string[];
}

export const CSF_FUNCTIONS: { code: CsfFunctionCode; nameEs: string; nameEn: string }[] = [
  { code: "GV", nameEs: "Gobernar", nameEn: "Govern" },
  { code: "ID", nameEs: "Identificar", nameEn: "Identify" },
  { code: "PR", nameEs: "Proteger", nameEn: "Protect" },
  { code: "DE", nameEs: "Detectar", nameEn: "Detect" },
  { code: "RS", nameEs: "Responder", nameEn: "Respond" },
  { code: "RC", nameEs: "Recuperar", nameEn: "Recover" },
];

